import React, { useState, useMemo } from 'react';

const styles = {
  app: {
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    minHeight: '100vh',
    padding: 20,
    boxSizing: 'border-box',
    display: 'flex',
    flexDirection: 'column',
    gap: 20,
  },
  section: {
    backgroundColor: '#0F1620',
    border: '1px solid #1F2A37',
    borderRadius: 10,
    padding: 16,
  },
  label: {
    display: 'block',
    marginBottom: 8,
    fontWeight: '600',
    fontSize: 14,
  },
  input: {
    width: '100%',
    padding: '8px 10px',
    borderRadius: 6,
    border: '1px solid #1F2A37',
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
  },
  select: {
    width: '100%',
    padding: '8px 10px',
    borderRadius: 6,
    border: '1px solid #1F2A37',
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
    fontSize: 14,
  },
  th: {
    borderBottom: '1px solid #1F2A37',
    padding: '8px 6px',
    textAlign: 'center',
    fontWeight: '600',
  },
  td: {
    borderBottom: '1px solid #1F2A37',
    padding: '6px 6px',
    textAlign: 'center',
  },
  button: {
    backgroundColor: '#1F2A37',
    border: '1px solid #1F2A37',
    borderRadius: 6,
    color: '#E5E7DB',
    padding: '6px 12px',
    cursor: 'pointer',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    marginTop: 8,
  },
  payoffChartContainer: {
    width: '100%',
    height: 300,
    backgroundColor: '#0F1620',
    border: '1px solid #1F2A37',
    borderRadius: 10,
    padding: 12,
    boxSizing: 'border-box',
  },
  greekSummary: {
    display: 'flex',
    gap: 20,
    flexWrap: 'wrap',
    fontSize: 14,
  },
  greekItem: {
    flex: '1 1 120px',
  },
  maxSummary: {
    marginTop: 12,
    fontSize: 14,
  },
  legTypeSelect: {
    width: '100%',
    padding: '4px 6px',
    borderRadius: 6,
    border: '1px solid #1F2A37',
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
  },
  legInput: {
    width: '100%',
    padding: '4px 6px',
    borderRadius: 6,
    border: '1px solid #1F2A37',
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    textAlign: 'center',
  },
};

const templates = {
  None: [],
  'Vertical Spread': [
    { buySell: 'Buy', type: 'Call', strikeOffset: -5, expirationOffset: 0, premium: 0 },
    { buySell: 'Sell', type: 'Call', strikeOffset: 0, expirationOffset: 0, premium: 0 },
  ],
  'Horizontal Spread': [
    { buySell: 'Buy', type: 'Put', strikeOffset: 0, expirationOffset: 0, premium: 0 },
    { buySell: 'Sell', type: 'Put', strikeOffset: 0, expirationOffset: 30, premium: 0 },
  ],
  Straddle: [
    { buySell: 'Buy', type: 'Call', strikeOffset: 0, expirationOffset: 0, premium: 0 },
    { buySell: 'Buy', type: 'Put', strikeOffset: 0, expirationOffset: 0, premium: 0 },
  ],
  'Strangle': [
    { buySell: 'Buy', type: 'Call', strikeOffset: 5, expirationOffset: 0, premium: 0 },
    { buySell: 'Buy', type: 'Put', strikeOffset: -5, expirationOffset: 0, premium: 0 },
  ],
};

function OptionsStrategyBuilder() {
  const [symbol, setSymbol] = useState('');
  const [price, setPrice] = useState('');
  const [template, setTemplate] = useState('None');
  const [legs, setLegs] = useState([]);

  // Update legs when template changes or price changes
  React.useEffect(() => {
    if (!price || isNaN(price)) {
      setLegs([]);
      return;
    }
    const basePrice = Number(price);
    if (template === 'None') {
      setLegs([]);
      return;
    }
    const newLegs = templates[template].map((leg, i) => ({
      id: i + 1,
      buySell: leg.buySell,
      type: leg.type,
      strike: Math.round(basePrice + leg.strikeOffset),
      expirationDays: leg.expirationOffset,
      premium: leg.premium,
    }));
    setLegs(newLegs);
  }, [template, price]);

  // Handlers for legs editing
  function updateLeg(id, field, value) {
    setLegs((ls) =>
      ls.map((leg) =>
        leg.id === id
          ? {
              ...leg,
              [field]:
                field === 'strike' || field === 'expirationDays' || field === 'premium'
                  ? Number(value)
                  : value,
            }
          : leg
      )
    );
  }

  // Calculate payoff and Greeks approx
  // Payoff at expiration for each leg:
  // Call: max(0, S - K) * (1 if Buy else -1) - premium * (1 if Buy else -1)
  // Put: max(0, K - S) * (1 if Buy else -1) - premium * (1 if Buy else -1)
  // Total payoff = sum of legs payoffs

  // Greeks approx by finite difference on price:
  // Delta ~ (payoff(S+1) - payoff(S-1)) / 2
  // Gamma ~ payoff(S+1) - 2*payoff(S) + payoff(S-1)
  // Theta ~ (payoff(S, T-1) - payoff(S, T)) (approximate by reducing expiration by 1 day)
  // Vega ~ (payoff with vol+1% - payoff with vol-1%) (not modeled here, so 0)
  // Rho ~ (payoff with rate+1% - payoff with rate-1%) (not modeled here, so 0)

  // For simplicity, we ignore volatility and interest rate effects, so Vega and Rho = 0

  // We calculate payoff at expiration only, so Theta is 0 (no time decay modeled)

  // We'll calculate payoff for a range of underlying prices for chart and breakeven

  const payoffAtPrice = (S, legsInput = legs) => {
    let total = 0;
    for (const leg of legsInput) {
      const sign = leg.buySell === 'Buy' ? 1 : -1;
      const K = leg.strike;
      const premium = leg.premium;
      if (leg.type === 'Call') {
        total += sign * (Math.max(0, S - K) - premium);
      } else {
        total += sign * (Math.max(0, K - S) - premium);
      }
    }
    return total;
  };

  const delta = useMemo(() => {
    if (legs.length === 0 || !price || isNaN(price)) return 0;
    const S = Number(price);
    return (payoffAtPrice(S + 1) - payoffAtPrice(S - 1)) / 2;
  }, [legs, price]);

  const gamma = useMemo(() => {
    if (legs.length === 0 || !price || isNaN(price)) return 0;
    const S = Number(price);
    return payoffAtPrice(S + 1) - 2 * payoffAtPrice(S) + payoffAtPrice(S - 1);
  }, [legs, price]);

  const theta = 0; // Not modeled
  const vega = 0; // Not modeled
  const rho = 0; // Not modeled

  // Max profit, max loss, breakeven points
  // We'll scan prices from 50% to 150% of underlying price in 100 steps
  // Find max and min payoff and breakeven points (where payoff crosses 0)

  const priceRange = useMemo(() => {
    if (!price || isNaN(price)) return [];
    const S = Number(price);
    const minP = Math.max(0, Math.floor(S * 0.5));
    const maxP = Math.ceil(S * 1.5);
    const step = (maxP - minP) / 100;
    const arr = [];
    for (let p = minP; p <= maxP; p += step) {
      arr.push(p);
    }
    return arr;
  }, [price]);

  const payoffs = useMemo(() => {
    if (priceRange.length === 0) return [];
    return priceRange.map((p) => ({ price: p, payoff: payoffAtPrice(p) }));
  }, [priceRange, legs]);

  const maxProfit = useMemo(() => {
    if (payoffs.length === 0) return null;
    const max = Math.max(...payoffs.map((p) => p.payoff));
    return max === Infinity ? 'Unlimited' : max.toFixed(2);
  }, [payoffs]);

  const maxLoss = useMemo(() => {
    if (payoffs.length === 0) return null;
    const min = Math.min(...payoffs.map((p) => p.payoff));
    return min === -Infinity ? 'Unlimited' : min.toFixed(2);
  }, [payoffs]);

  const breakevens = useMemo(() => {
    if (payoffs.length === 0) return [];
    const res = [];
    for (let i = 1; i < payoffs.length; i++) {
      const prev = payoffs[i - 1];
      const curr = payoffs[i];
      if (prev.payoff === 0) res.push(prev.price.toFixed(2));
      if ((prev.payoff < 0 && curr.payoff > 0) || (prev.payoff > 0 && curr.payoff < 0)) {
        // Linear interpolate zero crossing
        const slope = (curr.payoff - prev.payoff) / (curr.price - prev.price);
        const zeroCross = prev.price - prev.payoff / slope;
        res.push(zeroCross.toFixed(2));
      }
    }
    return res;
  }, [payoffs]);

  // SVG payoff chart
  // X axis: underlying price range
  // Y axis: payoff range
  // We'll map priceRange and payoffs to SVG coordinates

  const svgWidth = 600;
  const svgHeight = 280;
  const margin = { top: 20, right: 40, bottom: 40, left: 60 };

  const payoffMin = useMemo(() => {
    if (payoffs.length === 0) return 0;
    return Math.min(...payoffs.map((p) => p.payoff));
  }, [payoffs]);

  const payoffMax = useMemo(() => {
    if (payoffs.length === 0) return 0;
    return Math.max(...payoffs.map((p) => p.payoff));
  }, [payoffs]);

  // Prevent zero range
  const yMin = payoffMin < 0 ? payoffMin : 0;
  const yMax = payoffMax > 0 ? payoffMax : 0;

  // Scale functions
  const xScale = (x) =>
    margin.left + ((x - priceRange[0]) / (priceRange[priceRange.length - 1] - priceRange[0])) * (svgWidth - margin.left - margin.right);

  const yScale = (y) => {
    if (yMax === yMin) return svgHeight / 2;
    return margin.top + ((yMax - y) / (yMax - yMin)) * (svgHeight - margin.top - margin.bottom);
  };

  // Path for payoff line
  const payoffPath = payoffs.length
    ? payoffs
        .map((p, i) => {
          const x = xScale(p.price);
          const y = yScale(p.payoff);
          return `${i === 0 ? 'M' : 'L'}${x.toFixed(2)} ${y.toFixed(2)}`;
        })
        .join(' ')
    : '';

  // Axis ticks
  const xTicksCount = 6;
  const yTicksCount = 6;

  const xTicks = [];
  if (priceRange.length > 0) {
    const step = (priceRange[priceRange.length - 1] - priceRange[0]) / (xTicksCount - 1);
    for (let i = 0; i < xTicksCount; i++) {
      const val = priceRange[0] + step * i;
      xTicks.push(val);
    }
  }

  const yTicks = [];
  if (yMax !== yMin) {
    const step = (yMax - yMin) / (yTicksCount - 1);
    for (let i = 0; i < yTicksCount; i++) {
      const val = yMin + step * i;
      yTicks.push(val);
    }
  }

  return (
    <div style={styles.app}>
      <section style={styles.section}>
        <label htmlFor="symbol" style={styles.label}>
          Symbol
        </label>
        <input
          id="symbol"
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value.toUpperCase())}
          style={styles.input}
          placeholder="e.g. AAPL"
          spellCheck={false}
          autoComplete="off"
        />
      </section>

      <section style={styles.section}>
        <label htmlFor="price" style={styles.label}>
          Underlying Price
        </label>
        <input
          id="price"
          type="number"
          min="0"
          step="0.01"
          value={price}
          onChange={(e) => setPrice(e.target.value)}
          style={styles.input}
          placeholder="e.g. 150.00"
        />
      </section>

      <section style={styles.section}>
        <label htmlFor="template" style={styles.label}>
          Template
        </label>
        <select
          id="template"
          value={template}
          onChange={(e) => setTemplate(e.target.value)}
          style={styles.select}
        >
          {Object.keys(templates).map((key) => (
            <option key={key} value={key}>
              {key}
            </option>
          ))}
        </select>
      </section>

      <section style={styles.section}>
        <label style={styles.label}>Legs</label>
        {legs.length === 0 && <div style={{ fontStyle: 'italic' }}>No legs defined</div>}
        {legs.length > 0 && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Buy/Sell</th>
                <th style={styles.th}>Call/Put</th>
                <th style={styles.th}>Strike</th>
                <th style={styles.th}>Expiration (days)</th>
                <th style={styles.th}>Premium</th>
                <th style={styles.th}>Remove</th>
              </tr>
            </thead>
            <tbody>
              {legs.map((leg) => (
                <tr key={leg.id}>
                  <td style={styles.td}>
                    <select
                      value={leg.buySell}
                      onChange={(e) => updateLeg(leg.id, 'buySell', e.target.value)}
                      style={styles.legTypeSelect}
                    >
                      <option>Buy</option>
                      <option>Sell</option>
                    </select>
                  </td>
                  <td style={styles.td}>
                    <select
                      value={leg.type}
                      onChange={(e) => updateLeg(leg.id, 'type', e.target.value)}
                      style={styles.legTypeSelect}
                    >
                      <option>Call</option>
                      <option>Put</option>
                    </select>
                  </td>
                  <td style={styles.td}>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={leg.strike}
                      onChange={(e) => updateLeg(leg.id, 'strike', e.target.value)}
                      style={styles.legInput}
                    />
                  </td>
                  <td style={styles.td}>
                    <input
                      type="number"
                      min="0"
                      step="1"
                      value={leg.expirationDays}
                      onChange={(e) => updateLeg(leg.id, 'expirationDays', e.target.value)}
                      style={styles.legInput}
                    />
                  </td>
                  <td style={styles.td}>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={leg.premium}
                      onChange={(e) => updateLeg(leg.id, 'premium', e.target.value)}
                      style={styles.legInput}
                    />
                  </td>
                  <td style={styles.td}>
                    <button
                      type="button"
                      onClick={() => setLegs((ls) => ls.filter((l) => l.id !== leg.id))}
                      style={{ ...styles.button, padding: '2px 8px', fontSize: 13 }}
                      aria-label="Remove leg"
                    >
                      ×
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
        <button
          type="button"
          onClick={() => {
            const maxId = legs.reduce((max, l) => (l.id > max ? l.id : max), 0);
            setLegs((ls) => [
              ...ls,
              {
                id: maxId + 1,
                buySell: 'Buy',
                type: 'Call',
                strike: price ? Math.round(Number(price)) : 100,
                expirationDays: 30,
                premium: 0,
              },
            ]);
            setTemplate('None');
          }}
          style={styles.button}
        >
          Add Leg
        </button>
      </section>

      <section style={{ ...styles.section, ...styles.payoffChartContainer }}>
        <svg width={svgWidth} height={svgHeight} role="img" aria-label="Options strategy payoff chart">
          {/* Background */}
          <rect width="100%" height="100%" fill="#0F1620" />
          {/* Axes */}
          <line
            x1={margin.left}
            y1={yScale(0)}
            x2={svgWidth - margin.right}
            y2={yScale(0)}
            stroke="#1F2A37"
            strokeWidth={1}
          />
          <line
            x1={margin.left}
            y1={margin.top}
            x2={margin.left}
            y2={svgHeight - margin.bottom}
            stroke="#1F2A37"
            strokeWidth={1}
          />
          {/* X axis ticks and labels */}
          {xTicks.map((tick, i) => {
            const x = xScale(tick);
            return (
              <g key={i} transform={`translate(${x},${yScale(0)})`}>
                <line y2={6} stroke="#1F2A37" strokeWidth={1} />
                <text
                  y={20}
                  textAnchor="middle"
                  fill="#E5E7DB"
                  fontSize="12"
                  fontFamily="'JetBrains Mono', monospace"
                >
                  {tick.toFixed(0)}
                </text>
              </g>
            );
          })}
          {/* Y axis ticks and labels */}
          {yTicks.map((tick, i) => {
            const y = yScale(tick);
            return (
              <g key={i} transform={`translate(${margin.left},${y})`}>
                <line x1={-6} stroke="#1F2A37" strokeWidth={1} />
                <text
                  x={-10}
                  y={4}
                  textAnchor="end"
                  fill="#E5E7DB"
                  fontSize="12"
                  fontFamily="'JetBrains Mono', monospace"
                >
                  {tick.toFixed(0)}
                </text>
              </g>
            );
          })}
          {/* Payoff line */}
          <path d={payoffPath} fill="none" stroke="#4FD1C5" strokeWidth={2} />
          {/* Current price vertical line */}
          {price && !isNaN(price) && (
            <line
              x1={xScale(Number(price))}
              y1={margin.top}
              x2={xScale(Number(price))}
              y2={svgHeight - margin.bottom}
              stroke="#E53E3E"
              strokeWidth={1}
              strokeDasharray="4 4"
            />
          )}
        </svg>
      </section>

      <section style={styles.section}>
        <div style={styles.greekSummary}>
          <div style={styles.greekItem}>
            <strong>Delta:</strong> {delta.toFixed(2)}
          </div>
          <div style={styles.greekItem}>
            <strong>Gamma:</strong> {gamma.toFixed(2)}
          </div>
          <div style={styles.greekItem}>
            <strong>Theta:</strong> {theta.toFixed(2)}
          </div>
          <div style={styles.greekItem}>
            <strong>Vega:</strong> {vega.toFixed(2)}
          </div>
          <div style={styles.greekItem}>
            <strong>Rho:</strong> {rho.toFixed(2)}
          </div>
        </div>
        <div style={styles.maxSummary}>
          <div>
            <strong>Max Profit:</strong> {maxProfit}
          </div>
          <div>
            <strong>Max Loss:</strong> {maxLoss}
          </div>
          <div>
            <strong>Breakeven:</strong>{' '}
            {breakevens.length > 0 ? breakevens.join(', ') : 'None'}
          </div>
        </div>
      </section>
    </div>
  );
}

export default OptionsStrategyBuilder;
